sql:
SELECT category, SUM(full_time_men + full_time_women) AS total_full_time_students
FROM graduate_enrollment
GROUP BY category;

SELECT program_name
FROM degree_programs
WHERE total_enrolled > 50;

SELECT DISTINCT academic_year
FROM enrollment_statistics
ORDER BY academic_year;

external_knowledge:
External knowledge:

* The term 'degree-seeking' refers to students who are actively pursuing a degree; 
* 'Full-time' and 'part-time' enrollment statuses are based on the number of credits taken by students during an academic term;
* The 'percentage_men' and 'percentage_women' are calculated based on the total enrolled students in each program;
* The 'academic_year' is the period when the enrollment statistics are recorded.

sql:
SELECT program_name
FROM degree_programs
ORDER BY program_name;

SELECT full_time_men
FROM enrollment_statistics
WHERE academic_year = '2022-2023';

SELECT category, (full_time_men + full_time_women) AS total_full_time_students
FROM graduate_enrollment
ORDER BY total_full_time_students DESC;

SELECT category, programs
FROM graduate_enrollment
ORDER BY category;

SELECT program_name
FROM degree_programs
ORDER BY total_enrolled DESC;

SELECT program_name
FROM degree_programs
WHERE total_enrolled > 100;

SELECT program_name
FROM degree_programs
ORDER BY program_name ASC;
